/* C shim: EINTR-safe recv wrapper.
 * SIGCHLD (or any signal) can interrupt blocking recv/send/read,
 * returning -1 with errno==EINTR. Without a retry loop, the caller
 * interprets -1 as EOF or error and drops the connection.
 */
int ffi_bv_recv(int fd, unsigned char *buf, int offset, int maxlen) {
    ssize_t n;
    do {
        n = recv(fd, buf + offset, maxlen, 0);
    } while (n < 0 && errno == EINTR);
    if (n < 0) return -1;
    return (int)n;
}

int ffi_bv_send(int fd, const unsigned char *buf, int offset, int len) {
    ssize_t n;
    do {
        n = send(fd, buf + offset, len, MSG_NOSIGNAL);
    } while (n < 0 && errno == EINTR);
    if (n < 0) return -errno;
    return (int)n;
}

int ffi_bv_read_nonblock(int fd, unsigned char *buf, int offset, int max_len) {
    ssize_t n;
    do {
        n = read(fd, buf + offset, max_len);
    } while (n < 0 && errno == EINTR);
    if (n < 0) {
        if (errno == EAGAIN || errno == EWOULDBLOCK) return 0;
        return -1;
    }
    if (n == 0) return -1; /* EOF */
    return (int)n;
}

/* C shim: open /dev/null for any closed standard fds.
 * Call this at the start of a daemonized process.
 *
 * Problem: ffi_fork_exec closes ALL fds in the child before exec.
 * When the daemon later opens files/sockets, the kernel assigns
 * the lowest available fd numbers — which are 0, 1, 2. This causes
 * fd collisions: a socket gets fd 1 (stdout), and any Chez port
 * output goes to the socket instead of nowhere.
 */
int ffi_ensure_std_fds(void) {
    int count = 0;
    for (int fd = 0; fd <= 2; fd++) {
        if (fcntl(fd, F_GETFD) == -1 && errno == EBADF) {
            int nfd = open("/dev/null", (fd == 0) ? O_RDONLY : O_WRONLY);
            if (nfd >= 0 && nfd != fd) {
                dup2(nfd, fd);
                close(nfd);
            }
            count++;
        }
    }
    return count;
}

