// Problem: rusqlite::Statement borrows Connection.
// Can't store them in separate HashMaps.
//
// Solution: Use rusqlite only for Connection::open (proper init),
// then extract raw sqlite3* handle and use rusqlite::ffi C API
// directly for all statement operations.

struct DbEntry {
    _conn: Connection,  // keep alive for lifetime
    raw: *mut rusqlite::ffi::sqlite3,
}

struct StmtEntry {
    raw: *mut rusqlite::ffi::sqlite3_stmt,
    db_handle: u64,
}

// Open: use rusqlite, extract raw handle
let conn = Connection::open_in_memory()?;
let raw = unsafe { conn.handle() };

// Prepare: use sqlite3_prepare_v2 directly
let mut raw_stmt = std::ptr::null_mut();
unsafe {
    rusqlite::ffi::sqlite3_prepare_v2(
        raw, sql_ptr, sql_len as i32,
        &mut raw_stmt, std::ptr::null_mut());
}

// Bind/step/column: all via rusqlite::ffi::sqlite3_*
unsafe { rusqlite::ffi::sqlite3_bind_int64(raw_stmt, 1, value); }
unsafe { rusqlite::ffi::sqlite3_step(raw_stmt); }
unsafe { rusqlite::ffi::sqlite3_column_text(raw_stmt, 0); }

// Syscall numbers for x86_64
const SYS_LANDLOCK_CREATE_RULESET: libc::c_long = 444;
const SYS_LANDLOCK_ADD_RULE: libc::c_long = 445;
const SYS_LANDLOCK_RESTRICT_SELF: libc::c_long = 446;

#[repr(C)]
struct LandlockRulesetAttr {
    handled_access_fs: u64,
    handled_access_net: u64,
}

#[repr(C)]
struct LandlockPathBeneathAttr {
    allowed_access: u64,
    parent_fd: i32,
}

// Create ruleset
let fd = unsafe {
    libc::syscall(SYS_LANDLOCK_CREATE_RULESET,
        &attr as *const _, std::mem::size_of::<LandlockRulesetAttr>(), 0u32)
};

// Add path rule: open path with O_PATH, pass fd
let parent_fd = unsafe {
    libc::open(path_cstr, libc::O_PATH | libc::O_CLOEXEC)
};
let attr = LandlockPathBeneathAttr { allowed_access, parent_fd };
unsafe {
    libc::syscall(SYS_LANDLOCK_ADD_RULE, ruleset_fd, 1u32, &attr as *const _, 0u32);
    libc::close(parent_fd);
};

// Enforce: prctl + restrict_self
unsafe { libc::prctl(libc::PR_SET_NO_NEW_PRIVS, 1, 0, 0, 0); }
unsafe { libc::syscall(SYS_LANDLOCK_RESTRICT_SELF, ruleset_fd, 0u32); }

